def parse_wkt_point(wkt: str) -> tuple[float, float]:
    wkt = wkt.strip()
    if wkt.startswith("POINT("):
        wkt = wkt[6:-1]
        parts = wkt.split(" ")
        if len(parts) == 2:
            lon, lat = float(parts[0]), float(parts[1])
            return (lon, lat)
    return (0.0, 0.0)

